class Solution {
public:
    long long minSumSquareDiff(vector<int>& nums1, vector<int>& nums2, int k1, int k2) {
        int n = nums1.size();
        long long sum = 0;
        for (int i = 0; i < n; i++) {
            sum += (nums1[i] - nums2[i]) * (nums1[i] - nums2[i]);
        }
        long long diff = 0;
        for (int i = 0; i < n; i++) {
            diff += abs(nums1[i] - nums2[i]);
        }
        long long res = sum;
        for (int i = 0; i < n; i++) {
            long long temp = 0;
            if (k1 >= abs(nums1[i] - nums2[i]) / 2) {
                k1 -= abs(nums1[i] - nums2[i]) / 2;
                temp = (nums1[i] - nums2[i]) * (abs(nums1[i] - nums2[i]) / 2);
                nums1[i] = nums2[i];
            }
            if (k2 >= abs(nums1[i] - nums2[i]) / 2) {
                k2 -= abs(nums1[i] - nums2[i]) / 2;
                temp += (nums1[i] - nums2[i]) * (abs(nums1[i] - nums2[i]) / 2);
                nums2[i] = nums1[i];
            }
            res = min(res, sum - temp * 2);
        }
        return res;
    }
};
